  1→import { useEffect, useMemo, useRef, useState } from "react";
  2→import { Image as KonvaImage, Layer, Line, Rect, Stage, Text } from "react-konva";
  3→import { BarLoader } from "react-spinners";
  4→import { useQueryClient } from "@tanstack/react-query";
  5→import { saveJournal, saveJournalImage } from "../../../../API/Api";
  6→import { useAuth } from "../../../Context/useAuth";
  7→import { parseCanvasDoc } from "../../../utils/canvasDoc";
  8→import "./canvas.css";
  9→
 10→const FONT_BRUSHES = {
 11→    serif: {label: "Serif", fontFamily: "Georgia", fontStyle: "normal"},
 12→    mono: {label: "Mono", fontFamily: "Courier New", fontStyle: "normal"},
 13→    handwritten: {label: "Hand", fontFamily: "Comic Sans MS", fontStyle: "normal"},
 14→    bold: {label: "Bold", fontFamily: "Trebuchet MS", fontStyle: "bold"},
 15→};
 16→
 17→const GRID_SIZE = 24;
 18→const CANVAS_MAX_WIDTH = 560;
 19→const DOODLE_COLOR_PRESETS = [
 20→    "#5f92ff",
 21→    "#ff4d6d",
 22→    "#ff7f11",
 23→    "#ffd23f",
 24→    "#22c55e",
 25→    "#14b8a6",
 26→    "#8b5cf6",
 27→    "#111827",
 28→    "#ffffff"
 29→];
 30→
 31→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
 32→const createId = (prefix) => `${prefix}-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
 33→const sanitizeNormalizedPoints = (rawPoints) => {
 34→    if(!Array.isArray(rawPoints)){
 35→        return [];
 36→    }
 37→
 38→    const numericPoints = rawPoints
 39→        .map((point) => Number(point))
 40→        .filter((point) => !Number.isNaN(point))
 41→        .map((point) => clamp(point, 0, 1));
 42→
 43→    if(numericPoints.length < 2){
 44→        return [];
 45→    }
 46→
 47→    return numericPoints.length % 2 === 0
 48→        ? numericPoints
 49→        : numericPoints.slice(0, -1);
 50→};
 51→
 52→const getStageHeight = (width, aspectRatio) => {
 53→    if(aspectRatio === "4:5"){
 54→        return Math.round(width * 1.25);
 55→    }
 56→    return width;
 57→};
 58→
 59→const getSnippetMetrics = (snippet, stageWidth) => {
 60→    const sizeScale = Number.isFinite(snippet.sizeScale) ? snippet.sizeScale : 1;
 61→    const baseFontSize = snippet.fontStyle === "bold" ? 34 : snippet.fontStyle === "handwritten" ? 32 : 30;
 62→    const fontSize = clamp(baseFontSize * sizeScale, 18, 92);
 63→    const estimatedWidth = Math.max(120, Math.min(stageWidth * 0.78, Math.round((snippet.text.length || 1) * fontSize * 0.58)));
 64→    const charsPerLine = Math.max(8, Math.floor(estimatedWidth / (fontSize * 0.56)));
 65→    const lineCount = Math.max(1, Math.ceil((snippet.text.length || 1) / charsPerLine));
 66→    const height = Math.max(68, Math.round(lineCount * fontSize * 1.14 + 18));
 67→
 68→    return {width: estimatedWidth, height, fontSize};
 69→};
 70→
 71→const useLoadedImage = (src) => {
 72→    const [image, setImage] = useState(null);
 73→
 74→    useEffect(() => {
 75→        if(!src){
 76→            setImage(null);
 77→            return;
 78→        }
 79→
 80→        const img = new window.Image();
 81→        img.crossOrigin = "anonymous";
 82→        img.onload = () => setImage(img);
 83→        img.onerror = () => setImage(null);
 84→        img.src = src;
 85→
 86→        return () => {
 87→            img.onload = null;
 88→            img.onerror = null;
 89→        };
 90→    }, [src]);
 91→
 92→    return image;
 93→};
 94→
 95→const CanvasImageNode = ({canvasImage, stageWidth, stageHeight, isSelected, onSelect, onDragEnd, canInteract}) => {
 96→    const loadedImage = useLoadedImage(canvasImage?.src);
 97→    const objectWidth = clamp((canvasImage?.width || 0.3) * stageWidth, 56, stageWidth * 0.95);
 98→    const objectHeight = clamp((canvasImage?.height || 0.3) * stageHeight, 56, stageHeight * 0.95);
 99→    const x = clamp((canvasImage?.x || 0) * stageWidth, 0, Math.max(0, stageWidth - objectWidth));
100→    const y = clamp((canvasImage?.y || 0) * stageHeight, 0, Math.max(0, stageHeight - objectHeight));
101→
102→    return (
103→        <>
104→            <KonvaImage
105→                x={x}
106→                y={y}
107→                width={objectWidth}
108→                height={objectHeight}
109→                image={loadedImage}
110→                draggable={canInteract}
111→                rotation={canvasImage?.rotation || 0}
112→                scaleX={canvasImage?.scaleX === -1 ? -1 : 1}
113→                shadowColor="rgba(0,0,0,0.24)"
114→                shadowBlur={8}
115→                shadowOffsetY={3}
116→                onClick={canInteract ? onSelect : undefined}
117→                onTap={canInteract ? onSelect : undefined}
118→                onDragEnd={onDragEnd}
119→            />
120→            {isSelected && (
121→                <Rect
122→                    x={x}
123→                    y={y}
124→                    width={objectWidth}
125→                    height={objectHeight}
126→                    stroke="#2f80ed"
127→                    strokeWidth={1.6}
128→                    dash={[6, 4]}
129→                    rotation={canvasImage?.rotation || 0}
130→                    listening={false}
131→                />
132→            )}
133→        </>
134→    );
135→};
136→
137→const CanvasEditor = ({title, onCloseOnSave, addUploadedImagePath, initialCanvasDoc = null, remixSource = null}) => {
138→    const {session, user} = useAuth();
139→    const queryClient = useQueryClient();
140→    const shellRef = useRef(null);
141→    const hasHydratedInitialDocRef = useRef(false);
142→    const snippetInputRef = useRef(null);
143→    const doodlePointsRef = useRef([]);
144→    const [shellWidth, setShellWidth] = useState(CANVAS_MAX_WIDTH);
145→
146→    const [activeTool, setActiveTool] = useState("select");
147→    const [isSnippetComposerOpen, setIsSnippetComposerOpen] = useState(false);
148→    const [snippetInput, setSnippetInput] = useState("");
149→    const [selectedObject, setSelectedObject] = useState(null); // {kind: 'snippet'|'image', id}
150→    const [isSending, setIsSending] = useState(false);
151→    const [isUploadingImage, setIsUploadingImage] = useState(false);
152→    const [doodleColor, setDoodleColor] = useState("#5f92ff");
153→    const [doodleSize, setDoodleSize] = useState(2.8);
154→    const [isDrawing, setIsDrawing] = useState(false);
155→    const [currentDoodlePoints, setCurrentDoodlePoints] = useState([]);
156→    const [canvasMeta, setCanvasMeta] = useState({
157→        aspectRatio: "1:1",
158→        gridEnabled: true,
159→        snapEnabled: true,
160→        theme: "light"
161→    });
162→    const [snippets, setSnippets] = useState([]);
163→    const [images, setImages] = useState([]);
164→    const [doodles, setDoodles] = useState([]);
165→
166→    useEffect(() => {
167→        if(hasHydratedInitialDocRef.current || !initialCanvasDoc){
168→            return;
169→        }
170→
171→        const parsedDoc = parseCanvasDoc(initialCanvasDoc);
172→        setCanvasMeta((prev) => ({
173→            ...prev,
174→            aspectRatio: parsedDoc?.meta?.aspectRatio === '4:5' ? '4:5' : '1:1',
175→            gridEnabled: Boolean(parsedDoc?.meta?.gridEnabled),
176→            theme: parsedDoc?.meta?.theme === 'dark' ? 'dark' : 'light'
177→        }));
178→        setSnippets((parsedDoc?.snippets || []).map((snippet) => ({
179→            ...snippet,
180→            id: snippet.id || createId('snippet'),
181→            zIndex: Number.isFinite(snippet?.zIndex) ? snippet.zIndex : 0
182→        })));
183→        setImages((parsedDoc?.images || []).map((image) => ({
184→            ...image,
185→            id: image.id || createId('image'),
186→            zIndex: Number.isFinite(image?.zIndex) ? image.zIndex : 0
187→        })));
188→        setDoodles((parsedDoc?.doodles || []).map((doodle) => ({
189→            ...doodle,
190→            id: doodle.id || createId('doodle'),
191→            points: sanitizeNormalizedPoints(doodle.points)
192→        })));
193→        hasHydratedInitialDocRef.current = true;
194→    }, [initialCanvasDoc]);
195→
196→    useEffect(() => {
197→        const updateShellWidth = () => {
198→            const nextWidth = shellRef.current?.clientWidth || CANVAS_MAX_WIDTH;
199→            setShellWidth(nextWidth);
200→        };
201→
202→        updateShellWidth();
203→        window.addEventListener("resize", updateShellWidth);
204→
205→        let resizeObserver = null;
206→        if(typeof ResizeObserver !== "undefined" && shellRef.current){
207→            resizeObserver = new ResizeObserver(updateShellWidth);
208→            resizeObserver.observe(shellRef.current);
209→        }
210→
211→        return () => {
212→            window.removeEventListener("resize", updateShellWidth);
213→            if(resizeObserver){
214→                resizeObserver.disconnect();
215→            }
216→        };
217→    }, []);
218→
219→    useEffect(() => {
220→        if(!isSnippetComposerOpen){
221→            return;
222→        }
223→
224→        const frame = window.requestAnimationFrame(() => {
225→            snippetInputRef.current?.focus();
226→        });
227→
228→        return () => window.cancelAnimationFrame(frame);
229→    }, [isSnippetComposerOpen]);
230→
231→    useEffect(() => {
232→        if(activeTool !== "doodle"){
233→            doodlePointsRef.current = [];
234→            setCurrentDoodlePoints([]);
235→            setIsDrawing(false);
236→        }
237→    }, [activeTool]);
238→
239→    const stageWidth = useMemo(() => Math.max(280, Math.min(CANVAS_MAX_WIDTH, shellWidth - 24)), [shellWidth]);
240→    const stageHeight = getStageHeight(stageWidth, canvasMeta.aspectRatio);
241→
242→    const getNextZIndex = () => {
243→        const allZ = [
244→            ...snippets.map((snippet) => snippet.zIndex || 0),
245→            ...images.map((image) => image.zIndex || 0)
246→        ];
247→        return allZ.length ? Math.max(...allZ) + 1 : 0;
248→    };
249→
250→    const sortedObjects = useMemo(() => {
251→        const snippetObjects = snippets.map((snippet) => ({kind: "snippet", payload: snippet}));
252→        const imageObjects = images.map((image) => ({kind: "image", payload: image}));
253→        return [...snippetObjects, ...imageObjects].sort((a, b) => (a.payload?.zIndex || 0) - (b.payload?.zIndex || 0));
254→    }, [snippets, images]);
255→
256→    const selectedSnippet = selectedObject?.kind === "snippet"
257→        ? snippets.find((snippet) => snippet.id === selectedObject.id) || null
258→        : null;
259→    const selectedImage = selectedObject?.kind === "image"
260→        ? images.find((image) => image.id === selectedObject.id) || null
261→        : null;
262→    const canEditObjects = activeTool === "select";
263→
264→    const updateSnippet = (snippetId, updater) => {
265→        setSnippets((prev) => prev.map((snippet) => {
266→            if(snippet.id !== snippetId){
267→                return snippet;
268→            }
269→            const nextValue = typeof updater === "function" ? updater(snippet) : updater;
270→            return {...snippet, ...nextValue};
271→        }));
272→    };
273→
274→    const updateImage = (imageId, updater) => {
275→        setImages((prev) => prev.map((image) => {
276→            if(image.id !== imageId){
277→                return image;
278→            }
279→            const nextValue = typeof updater === "function" ? updater(image) : updater;
280→            return {...image, ...nextValue};
281→        }));
282→    };
283→
284→    const addSnippet = () => {
285→        const trimmed = snippetInput.trim();
286→        if(!trimmed){
287→            return;
288→        }
289→
290→        const snippet = {
291→            id: createId("snippet"),
292→            text: trimmed,
293→            x: 0.16,
294→            y: 0.2,
295→            rotation: 0,
296→            fontStyle: "serif",
297→            scaleX: 1,
298→            sizeScale: 1,
299→            zIndex: getNextZIndex()
300→        };
301→        setSnippets((prev) => [...prev, snippet]);
302→        setSelectedObject({kind: "snippet", id: snippet.id});
303→        setSnippetInput("");
